class Solution:
    def shiftingLetters(self, s, shifts):
        n = len(s)
        res = list(s)
        # apply each prefix shift independently (naive O(n^2))
        offset = [0] * n
        for i in range(n):
            for j in range(i + 1):
                offset[j] += shifts[i]
        for j in range(n):
            res[j] = chr((ord(s[j]) - 97 + offset[j]) % 26 + 97)
        return ''.join(res)

