var shiftingLetters = function(s, shifts) {
    const n = s.length;
    const res = new Array(n);
    let total = 0;
    for (let i = n - 1; i >= 0; i--) {
        total = (total + (shifts[i] % 26)) % 26;
        const c = (s.charCodeAt(i) - 97 + total) % 26 + 97;
        res[i] = String.fromCharCode(c);
    }
    return res.join('');
};
